// A class is a template; each object is a separate instance
public class BankAccount {
    // --- Fields (instance variables) ---
    // Each object gets its own copy of these
    String owner;       // defaults to null
    double balance;     // defaults to 0.0
    int transCount;     // defaults to 0

    // --- Constructor ---
    // Called automatically when you write: new BankAccount("Alice", 500)
    public BankAccount(String owner, double initialBalance) {
        this.owner = owner;           // 'this' refers to the current object
        this.balance = initialBalance;
        this.transCount = 0;
    }

    // --- Instance Methods ---
    // 'this' is implicitly available inside every instance method
    public void deposit(double amount) {
        balance += amount;
        transCount++;
    }

    public boolean withdraw(double amount) {
        if (amount > balance) return false;
        balance -= amount;
        transCount++;
        return true;
    }

    public double getBalance() {
        return balance;
    }

    public String getSummary() {
        return owner + ": $" + balance + " (" + transCount + " transactions)";
    }
}

// --- Driver class to test it ---
public class Main {
    public static void main(String[] args) {
        BankAccount acc = new BankAccount("Alice", 500.0);
        acc.deposit(200.0);
        System.out.println(acc.getBalance());    // 700.0
        System.out.println(acc.withdraw(1000.0)); // false
        System.out.println(acc.getSummary());     // Alice: $700.0 (1 transactions)
    }
}

public class StackVsHeap {
    public static void main(String[] args) {
        // Primitives: value is stored directly in the variable
        int x = 10;
        int y = x;   // y gets a COPY of the value 10
        y = 99;
        System.out.println(x); // 10 — x is unaffected

        // Objects: variable stores a REFERENCE (address), not the object itself
        BankAccount a = new BankAccount("Alice", 500);
        BankAccount b = a;  // b gets a COPY of the REFERENCE (address)
                            // Both a and b now point to the SAME heap object!

        b.deposit(100);     // modifies the shared object
        System.out.println(a.getBalance()); // 600.0 — a sees the change!

        // Create a truly independent object
        BankAccount c = new BankAccount("Carol", 500);
        c.deposit(100);     // only affects c's object
        System.out.println(a.getBalance()); // still 600.0
    }
}

public class Point {
    double x;
    double y;

    // Without 'this': parameter names shadow field names!
    public void setBadStyle(double x, double y) {
        x = x; // WRONG: assigns parameter to itself, fields stay at default 0.0
        y = y; // WRONG: same problem
    }

    // With 'this': unambiguous
    public void setGoodStyle(double x, double y) {
        this.x = x; // 'this.x' is the field; 'x' (right side) is the parameter
        this.y = y;
    }

    // No name conflict: 'this' optional but clarifying
    public double distanceTo(Point other) {
        double dx = this.x - other.x; // same as: dx = x - other.x
        double dy = this.y - other.y;
        return Math.sqrt(dx*dx + dy*dy);
    }

    // Passing 'this' as argument
    public void registerWith(PointRegistry registry) {
        registry.add(this); // passes the current Point object
    }

    public static void main(String[] args) {
        Point p = new Point();
        p.setBadStyle(3.0, 4.0);
        System.out.println(p.x + " " + p.y); // 0.0 0.0  (BUG!)

        Point q = new Point();
        q.setGoodStyle(3.0, 4.0);
        System.out.println(q.x + " " + q.y); // 3.0 4.0  (correct)
    }
}

public class RefDemo {

    // This method CAN modify the object's contents
    static void addFunds(BankAccount acc, double amount) {
        acc.deposit(amount);  // 'acc' refers to the same heap object as caller's variable
    }

    // This method CANNOT make the caller's variable point elsewhere
    static void replaceAccount(BankAccount acc) {
        acc = new BankAccount("Hacker", 9999); // only changes LOCAL copy of reference
        // caller's original variable is completely unaffected
    }

    public static void main(String[] args) {
        BankAccount myAcc = new BankAccount("Bob", 100.0);

        addFunds(myAcc, 50.0);
        System.out.println(myAcc.getBalance()); // 150.0 — object was modified

        replaceAccount(myAcc);
        System.out.println(myAcc.owner);        // Bob — NOT Hacker! reference unchanged
        System.out.println(myAcc.getBalance()); // 150.0 — same object
    }
}

public class NullDemo {
    String name;     // defaults to null
    int age;         // defaults to 0

    public static void main(String[] args) {
        NullDemo obj = new NullDemo(); // constructor NOT defined; uses default
        System.out.println(obj.age);   // 0
        System.out.println(obj.name);  // null (prints the word "null")

        // Calling a method on null -> NullPointerException!
        // System.out.println(obj.name.length()); // CRASH: NullPointerException

        // Defensive check:
        if (obj.name != null) {
            System.out.println(obj.name.length());
        } else {
            System.out.println("name is null");
        }

        // null reference check in condition
        NullDemo other = null;
        System.out.println(other == null); // true
        // other.age;  // NullPointerException — can't access fields of null
    }
}

public class Counter {
    int count;
    String label;

    public Counter(String label) {
        this.label = label;
        this.count = 0;
    }
    public void increment() { count++; }
    public void add(int n)   { count += n; }
    public void reset()      { count = 0; }
    public String toString() { return label + ": " + count; }

    public static void main(String[] args) {
        Counter a = new Counter("A");
        Counter b = new Counter("B");
        a.increment();
        a.increment();
        b.add(5);
        a.add(b.count);
        b.reset();
        System.out.println(a);
        System.out.println(b);
        b.increment();
        Counter c = a;
        c.increment();
        System.out.println(a);
        System.out.println(c == a);
    }
}

public class Box {
    int value;
    public Box(int v) { this.value = v; }

    static void doubleIt(Box b) {
        b.value *= 2;
    }

    static void replaceIt(Box b) {
        b = new Box(999);
    }

    static void swap(Box x, Box y) {
        int temp = x.value;
        x.value = y.value;
        y.value = temp;
    }

    public static void main(String[] args) {
        Box b1 = new Box(10);
        Box b2 = new Box(30);

        doubleIt(b1);
        System.out.println(b1.value);

        replaceIt(b2);
        System.out.println(b2.value);

        swap(b1, b2);
        System.out.println(b1.value + " " + b2.value);
    }
}

