// Design a Student class with:
//   Fields: name (String), grade (int)
//   Constructor: Student(String name, int grade)
//   Method: boolean hasBetterGrade(Student other)
//     Returns true if THIS student's grade > other's grade
//   Method: String toString()
//     Returns "name (grade)" e.g. "Alice (92)"
// Then in main:
//   Create two students, compare them, print the one with the better grade.

sections.solution:
public class Student {
    String name;
    int grade;

    public Student(String name, int grade) {
        this.name = name;
        this.grade = grade;
    }

    public boolean hasBetterGrade(Student other) {
        return this.grade > other.grade;
    }

    public String toString() {
        return name + " (" + grade + ")";
    }

    public static void main(String[] args) {
        Student s1 = new Student("Alice", 92);
        Student s2 = new Student("Bob",   87);

        if (s1.hasBetterGrade(s2)) {
            System.out.println(s1 + " has a better grade");
        } else if (s2.hasBetterGrade(s1)) {
            System.out.println(s2 + " has a better grade");
        } else {
            System.out.println("Both students have the same grade");
        }
        // Output: Alice (92) has a better grade
    }
}
